mapper.select:
SELECT c.*, u.avatar as user_avatar, u.nickname as user_nickname, s.name as service_name FROM service_comment c LEFT JOIN user u ON c.user_id = u.id LEFT JOIN service_item s ON c.service_id = s.id
AND (c.user_name LIKE CONCAT('%', #{keyword}, '%') OR c.content LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%'))
AND c.rating = #{rating}
AND c.status = #{status}
AND (c.reply IS NULL OR c.reply = '')
AND c.reply IS NOT NULL AND c.reply != ''
ORDER BY c.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM service_comment c LEFT JOIN service_item s ON c.service_id = s.id
AND (c.user_name LIKE CONCAT('%', #{keyword}, '%') OR c.content LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%'))
AND c.rating = #{rating}
AND c.status = #{status}
AND (c.reply IS NULL OR c.reply = '')
AND c.reply IS NOT NULL AND c.reply != ''

SELECT c.id, c.appointment_id, c.service_id, c.user_id, c.rating, c.content, c.images, c.reply, c.reply_time, c.status, c.create_time, c.update_time, u.username as user_name, u.nickname as user_nickname, u.avatar as user_avatar, s.name as service_name FROM service_comment c LEFT JOIN user u ON c.user_id = u.id LEFT JOIN service_item s ON c.service_id = s.id WHERE c.service_id = #{serviceId} AND c.status = 1
AND c.rating = #{rating}
ORDER BY c.create_time DESC LIMIT #{offset}, #{limit}
